/*
根据hex反序列号构造message
*/
func BuildMessageFromHex(hexStr string) *waE2E.Message {
	// 1、把 hex 字符串 → 转成 []byte
	data, err := hex.DecodeString(hexStr)
	if err != nil {
		panic(err)
	}

	// 2、反序列化 protobuf
	var msg waE2E.Message
	err = proto.Unmarshal(data, &msg)
	if err != nil {
		panic(err)
	}

	return &msg
}

/*
DeleteChat 删除你发给 toJid 的聊天，并同步到所有绑定设备
toJid 				: 	85259441368@s.whatsapp.net
lastMsgID 			: 	3EB024D180B105F2820562
lastMsgTimestamp	: 	176187949410:57:18.957
*/
func DeleteChat(waCli *whatsmeow.Client, toJid string, lastMsgID string, lastMsgTimestamp int64) error {
	ctx := context.Background()

	// 协议更新，原有的jid删除失效，需要lid
	jid, _ := types.ParseJID(toJid)
	toLID, _ := waCli.Store.LIDs.GetLIDForPN(ctx, jid)
	toLIDStr := fmt.Sprintf("%s", toLID)

	patch := newAppState(toLIDStr, lastMsgID, lastMsgTimestamp)
	// 发送 patch 到服务器
	if err := waCli.SendAppState(ctx, patch); err != nil {
		return fmt.Errorf("send appstate patch failed: %w", err)
	}
	return nil
}

// newAppState builds an app state patch for deleting a chat.
func newAppState(toLid string, lastMsgID string, lastMsgTimestamp int64) appstate.PatchInfo {
	action := &waSyncAction.DeleteChatAction{
		MessageRange: &waSyncAction.SyncActionMessageRange{
			LastMessageTimestamp: proto.Int64(lastMsgTimestamp),
			Messages: []*waSyncAction.SyncActionMessage{{
				Key: &waCommon.MessageKey{
					RemoteJID: proto.String(toLid), // 对方 LID
					FromMe:    proto.Bool(true),
					ID:        proto.String(lastMsgID),
				},
				Timestamp: proto.Int64(lastMsgTimestamp),
			}},
		},
	}
	return appstate.PatchInfo{
		Type: appstate.WAPatchRegularHigh,
		Mutations: []appstate.MutationInfo{{
			Index: []string{appstate.IndexDeleteChat, toLid, "1"}, // 这个1为同步到所有的关联设备，不传1则只会同步删除主设备的
			Value: &waSyncAction.SyncActionValue{
				DeleteChatAction: action,
			},
			//Version: 27,
		}},
	}
}

/*
	删除群聊会话
*/
/*
DeleteGroupChat 删除指定群聊的聊天记录（不退群）
groupJid            : 120363403574492441@g.us
lastMsgID           : 最后一条消息 ID
lastMsgTimestamp    : 最后一条消息时间戳（毫秒）
*/
func DeleteGroupChat(
	waCli *whatsmeow.Client,
	groupJid string,
	lastMsgID string,
	lastMsgTimestamp int64,
) error {
	ctx := context.Background()
	jid, _ := types.ParseJID(groupJid)
	patch := newGroupDeleteChatAppState(
		jid.String(),
		lastMsgID,
		lastMsgTimestamp,
	)
	// 发送 patch 到服务器
	if err := waCli.SendAppState(ctx, patch); err != nil {
		return fmt.Errorf("send group delete appstate failed: %w", err)
	}
	return nil
}

func newGroupDeleteChatAppState(
	groupJid string,
	lastMsgID string,
	lastMsgTimestamp int64,
) appstate.PatchInfo {
	action := &waSyncAction.DeleteChatAction{
		MessageRange: &waSyncAction.SyncActionMessageRange{
			LastMessageTimestamp: proto.Int64(lastMsgTimestamp),
			Messages: []*waSyncAction.SyncActionMessage{
				{
					Key: &waCommon.MessageKey{
						RemoteJID: proto.String(groupJid), // 群 JID
						FromMe:    proto.Bool(true),
						ID:        proto.String(lastMsgID),
					},
					Timestamp: proto.Int64(lastMsgTimestamp),
				},
			},
		},
	}
	return appstate.PatchInfo{
		Type: appstate.WAPatchRegularHigh,
		Mutations: []appstate.MutationInfo{
			{
				Index: []string{appstate.IndexDeleteChat, groupJid, "1"}, // 同步所有关联设备
				Value: &waSyncAction.SyncActionValue{
					DeleteChatAction: action,
				},
			},
		},
	}
}

/*
添加为联系人
*/
func AddContact(waCli *whatsmeow.Client, phoneNumber string) error {
	ctx := context.Background()

	// 转jid
	jid := types.NewJID(phoneNumber, "s.whatsapp.net")
	// 获取信息
	info, _ := waCli.GetUserInfo(ctx, []types.JID{jid})
	if info == nil {
		return nil
	}
	// 获取lid
	lid, _ := waCli.Store.LIDs.GetLIDForPN(ctx, jid)

	patch := appstate.PatchInfo{
		Type: appstate.WAPatchCriticalUnblockLow,
		Mutations: []appstate.MutationInfo{{
			Index: []string{appstate.IndexContact, phoneNumber, "1"},
			Value: &waSyncAction.SyncActionValue{
				ContactAction: &waSyncAction.ContactAction{
					FullName:                 proto.String(""),
					FirstName:                proto.String(phoneNumber),
					Username:                 proto.String(""),
					LidJID:                   proto.String(jid.String()),
					SaveOnPrimaryAddressbook: proto.Bool(false),
					PnJID:                    proto.String(lid.String()),
				},
			},
		}},
	}

	// 发送 patch 到服务器
	if err := waCli.SendAppState(ctx, patch); err != nil {
		return fmt.Errorf("send appstate patch failed: %w", err)
	}
	return nil
}

func rand5digits() (string, error) {
	n, err := crand.Int(crand.Reader, big.NewInt(100000)) // 0..99999
	if err != nil {
		return "", err
	}
	return fmt.Sprintf("%05d", n.Int64()), nil // 补足 5 位
}

func appendRandomKey(raw string) (string, error) {
	u, err := url.Parse(raw)
	if err != nil {
		return "", err
	}
	v := u.Query()
	randVal, err := rand5digits()
	if err != nil {
		return "", err
	}
	v.Set("key", randVal)
	u.RawQuery = v.Encode()
	return u.String(), nil
}

func CreateGroup(waCli *whatsmeow.Client, name string, numbers []string) string {
	// 1. create 群（只拉 1 人，降低风控）
	first := numbers[0]
	groupId, err := createGroupHandler(waCli, name, first)
	if err != nil {
		fmt.Printf("create group failed: %v\n", err)
	}

	// 2. 随机 sleep 3–10 秒
	sleepRandom(5, 10)

	// 3. 剩余成员分批 add
	rest := numbers[1:]
	err = batchAddParticipants(waCli, groupId, rest)
	if err != nil {
		fmt.Printf("batch add participants failed: %v\n", err)
	}

	return groupId
}

func createGroupHandler(waCli *whatsmeow.Client, name string, number string) (string, error) {
	ctx := context.Background()

	jid := types.NewJID(number, "s.whatsapp.net")

	// 防止重复创建的key id
	createKey := types.MessageID(waCli.GenerateMessageID())
	resp, err := waCli.CreateGroup(ctx, whatsmeow.ReqCreateGroup{
		// 群名称
		Name: name,
		// 初始成员
		Participants: []types.JID{jid},
		// 唯一id，防止网络波动，重复创建，可以根据初始成员jid md5
		CreateKey: createKey,
		// 阅后即焚 0 关闭
		GroupEphemeral: types.GroupEphemeral{
			DisappearingTimer: 0,
		},
		// true 只有管理员能发言，false 所有成员可发言
		GroupAnnounce: types.GroupAnnounce{
			IsAnnounce: false,
		},
		// 群信息锁定
		// true：只有管理员能 改群名 改头像 改描述
		// false：所有成员可改
		GroupLocked: types.GroupLocked{
			IsLocked: false,
		},
		// 入群是否需要管理员审批
		GroupMembershipApprovalMode: types.GroupMembershipApprovalMode{
			IsJoinApprovalRequired: false,
		},
	})

	if err != nil {
		return "", err
	}

	groupId := resp.JID.String()

	return groupId, err
}

func batchAddParticipants(waCli *whatsmeow.Client, groupId string, numbers []string) error {
	ctx := context.Background()
	groupJid := types.NewJID(groupId, "g.us")

	i := 0
	for i < len(numbers) {
		// 每批 1–5 人
		batchSize := rand.Intn(5) + 1
		end := i + batchSize
		if end > len(numbers) {
			end = len(numbers)
		}

		var batch []types.JID
		for _, number := range numbers[i:end] {
			batch = append(batch, types.NewJID(number, "s.whatsapp.net"))
		}

		_, err := waCli.UpdateGroupParticipants(
			ctx,
			groupJid,
			batch,
			whatsmeow.ParticipantChangeAdd,
		)
		if err != nil {
			return err
		}

		i = end

		// 每批之间 sleep 3–10 秒
		sleepRandom(5, 10)
	}

	return nil
}

// 生成指定范围内的随机延迟
func sleepRandom(minSec, maxSec int) {
	if maxSec <= minSec {
		time.Sleep(time.Duration(minSec) * time.Second)
		return
	}
	sec := rand.Intn(maxSec-minSec+1) + minSec
	time.Sleep(time.Duration(sec) * time.Second)
}
